 393|    fn buildWindowStatusList(self: *Server, alloc: std.mem.Allocator, session: *const Session, refresh_interval_ns: u64) ![]u8 {
 394|        var windows: std.ArrayListAligned(u8, null) = .empty;
 395|        errdefer windows.deinit(alloc);
 396|
 397|        const host_name = hostname();
 398|        for (session.windows.items, 0..) |window, idx| {
 399|            if (idx > 0) {
 400|                try windows.append(alloc, ' ');
 401|            }
 402|
 403|            const active_pane = window.active_pane;
 404|            const fmt_ctx = status_fmt.FormatContext{
 405|                .session_name = session.name,
 406|                .session_id = session.id,
 407|                .window_name = window.name,
 408|                .window_index = windowIndex(session, window),
 409|                .window_active = session.active_window == window,
 410|                .window_flags = windowFlags(session, window),
 411|                .pane_index = if (active_pane) |pane| paneIndex(window, pane) else 0,
 412|                .host = host_name,
 413|            };
 414|            const status_format = if (session.active_window == window)
 415|                window.options.window_status_current_format
 416|            else
 417|                window.options.window_status_format;
 418|            const expanded = try status_fmt.expandCached(alloc, status_format, &fmt_ctx, &self.status_command_cache, refresh_interval_ns);
 419|            defer alloc.free(expanded);
 420|            try windows.appendSlice(alloc, expanded);
 421|        }
 422|
 423|        return try windows.toOwnedSlice(alloc);
 424|    }
