 454|    fn renderStatusBar(self: *Server, out: *output_mod.Output, session: *const Session, window: *const Window, cols: u32, rows: u32) !void {
 455|        const row = statusRow(session, rows) orelse return;
 456|        const host_name = hostname();
 457|        const active_pane = window.active_pane;
 458|        const fmt_ctx = status_fmt.FormatContext{
 459|            .session_name = session.name,
 460|            .session_id = session.id,
 461|            .window_name = window.name,
 462|            .window_index = windowIndex(session, window),
 463|            .window_active = true,
 464|            .window_flags = windowFlags(session, window),
 465|            .pane_index = if (active_pane) |pane| paneIndex(window, pane) else 0,
 466|            .host = host_name,
 467|        };
 468|
 469|        const refresh_interval_ns = @as(u64, @max(session.options.status_interval, 1)) * std.time.ns_per_s;
 470|        const left = try status_fmt.expandCached(self.allocator, session.options.status_left, &fmt_ctx, &self.status_command_cache, refresh_interval_ns);
 471|        defer self.allocator.free(left);
 472|        const right = try status_fmt.expandCached(self.allocator, session.options.status_right, &fmt_ctx, &self.status_command_cache, refresh_interval_ns);
 473|        defer self.allocator.free(right);
 474|        const center = try self.buildWindowStatusList(self.allocator, session, refresh_interval_ns);
 475|        defer self.allocator.free(center);
 476|
 477|        const status_bar = status_mod.StatusBar{
 478|            .left = session.options.status_left,
 479|            .right = session.options.status_right,
 480|            .style = session.options.status_style,
 481|            .interval = session.options.status_interval,
 482|            .enabled = session.options.status,
 483|        };
 484|        const line = try status_bar.renderSections(self.allocator, cols, left, center, right);
 485|        defer self.allocator.free(line);
 486|
 487|        out.cursorTo(0, row);
 488|        writeStyledStatusLine(out, status_bar.style, line);
 489|        out.attrReset();
 490|    }
