 534|    fn hasPendingPaneWrites(self: *const Server) bool {
 535|        var iter = self.pending_pane_writes.iterator();
 536|        while (iter.next()) |entry| {
 537|            if (entry.value_ptr.items.len > 0) return true;
 538|        }
 539|        return false;
 540|    }
