 542|    fn hasClientForSession(self: *const Server, session: *Session) bool {
 543|        if (self.session_client_fds.getPtr(session)) |client_fds| {
 544|            return client_fds.items.len > 0;
 545|        }
 546|        for (self.clients.items) |client| {
 547|            if (client.session == session) return true;
 548|        }
 549|        return false;
 550|    }
