 552|    fn sessionClientFds(self: *const Server, session: *Session) []const std.c.fd_t {
 553|        return if (self.session_client_fds.getPtr(session)) |client_fds|
 554|            client_fds.items
 555|        else
 556|            &.{};
 557|    }
