 633|    fn flushAllPendingPaneWrites(self: *Server) void {
 634|        var pane_ids: [FdPoller.max_fds]u32 = undefined;
 635|        var pane_count: usize = 0;
 636|        var iter = self.pending_pane_writes.iterator();
 637|        while (iter.next()) |entry| {
 638|            if (pane_count >= pane_ids.len) break;
 639|            pane_ids[pane_count] = entry.key_ptr.*;
 640|            pane_count += 1;
 641|        }
 642|
 643|        for (pane_ids[0..pane_count]) |pane_id| {
 644|            if (self.findPaneRefById(pane_id)) |pane_ref| {
 645|                self.flushPendingPaneWrites(pane_ref.pane);
 646|            } else {
 647|                self.clearPendingPaneWrites(pane_id);
 648|            }
 649|        }
 650|    }
