 874|            .fd = client_fd,
 875|            .session = null,
 876|            .identified = false,
 877|            .choose_tree_state = null,
 878|            .client_id = client_id,
 879|        });
 880|        client_stream.socket.handle = -1;
 881|        self.drainClient(client_idx);
