 884|    /// Cross-platform std.Io-backed server runtime.
 885|    ///
 886|    /// `std.Io.Threaded` is the first-party stdlib backend that currently
 887|    /// supports the Unix-domain socket control plane zmux uses on both macOS
 888|    /// and Linux, while fd readiness is handled by the platform poller
 889|    /// (`kqueue` on macOS, `epoll` on Linux, `poll` fallback elsewhere).
 890|    pub fn run(self: *Server) !void {
 891|        return self.runPoll();
 892|    }
 893|
 894|    /// Cross-platform fd-readiness loop used by the std.Io-backed server runtime.
 895|    fn runPoll(self: *Server) !void {
 896|        var ready_fds: [FdPoller.max_fds]std.posix.fd_t = undefined;
 897|
 898|        while (self.running) {
 899|            if (signals.SignalHandler.shouldExit()) {
 900|                self.stop();
 901|                break;
 902|            }
 903|
 904|            var timeout_ms = self.nextPollTimeoutMs();
 905|            if (timeout_ms == 0) {
 906|                startup_probe.traceEvent("server", "timer_tick", "source=poll");
 907|                self.runMaintenanceTick();
 908|                timeout_ms = self.nextPollTimeoutMs();
 909|            }
 910|
 911|            const ready = try self.fd_poller.wait(timeout_ms, &ready_fds);
 912|            if (ready.len == 0) {
 913|                startup_probe.traceEvent("server", "timer_tick", "source=poll");
 914|                self.runMaintenanceTick();
 915|                continue;
 916|            }
 917|
 918|            for (ready) |fd| {
 919|                const owner = self.fdOwner(fd) orelse continue;
 920|                switch (owner) {
 921|                    .listen => self.acceptClient() catch {},
 922|                    .client => |client_idx| {
 923|                        if (client_idx >= self.clients.items.len or self.clients.items[client_idx].fd != fd) continue;
 924|                        var detail: [160]u8 = undefined;
 925|                        const msg = std.fmt.bufPrint(&detail, "source=poll client_id={d}", .{self.clients.items[client_idx].client_id}) catch "";
 926|                        startup_probe.traceEvent("server", "client_fd_event", msg);
 927|                        self.drainClient(client_idx);
 928|                    },
 929|                    .pane => |pane_id| {
 930|                        if (self.findPaneRefById(pane_id)) |pane_ref| {
 931|                            self.drainPaneReadableRef(pane_ref);
 932|                        }
 933|                    },
 934|                }
 935|            }
 936|        }
 937|    }
