 940|        self.running = false;
 941|        if (self.listen_fd >= 0) {
 942|            self.unregisterReadableFd(self.listen_fd);
 943|            _ = std.c.close(self.listen_fd);
 944|            self.listen_fd = -1;
 945|        }
 946|        var path_buf: [256]u8 = .{0} ** 256;
 947|        if (self.socket_path.len < path_buf.len) {
 948|            @memcpy(path_buf[0..self.socket_path.len], self.socket_path);
 949|            _ = std.c.unlink(@ptrCast(path_buf[0..self.socket_path.len :0]));
 950|        }
 951|    }
