 960|    pub fn removeSession(self: *Server, session: *Session) void {
 961|        for (session.windows.items) |window| {
 962|            for (window.panes.items) |pane| {
 963|                self.unregisterReadableFd(pane.fd);
 964|                self.unregisterPaneRef(pane.id);
