 970|            if (client.session == session) {
 971|                self.removeSessionClientFd(session, client.fd);
 972|                self.clearSessionRelayOwnerFd(session, client.fd);
 973|                client.session = null;
 974|            }
 975|        }
 976|        if (self.session_client_fds.fetchRemove(session)) |entry| {
 977|            var fds = entry.value;
 978|            fds.deinit(self.allocator);
 979|        }
 980|        _ = self.session_relay_owner_fds.remove(session);
 981|        for (self.sessions.items, 0..) |existing, i| {
 982|            if (existing == session) {
 983|                _ = self.sessions.orderedRemove(i);
 984|                break;
