1033|    fn handleClientReadable(self: *Server, client_idx: usize) !void {
1034|        const client = &self.clients.items[client_idx];
1035|        var message = protocol.recvMessageAllocNonblocking(self.allocator, client.fd, &client.recv_state) catch |err| switch (err) {
1036|            error.UnexpectedEof, error.ReadFailed => {
1037|                self.removeClient(client_idx);
1038|                return;
1039|            },
1040|            error.WouldBlock => return err, // no data yet, propagate to caller
1041|            else => return err,
1042|        };
1043|        defer message.deinit();
1044|
1045|        switch (message.msg_type) {
1046|            .identify => try self.handleIdentify(client_idx, message.payload),
1047|            .command => try self.handleCommand(client_idx, message.payload),
1048|            .key => self.handleClientKey(client_idx, message.payload),
1049|            .resize => self.handleClientResize(client_idx, message.payload),
1050|            .terminal_probe_ready => self.handleTerminalProbeReady(client_idx),
1051|            .terminal_probe_rsp => try self.handleTerminalProbeRsp(client_idx, message.payload),
1052|            .exit, .exiting => self.removeClient(client_idx),
1053|            .shell => {},
1054|            else => {},
1055|        }
1056|    }
