1066|        self.clients.items[client_idx].cols = if (ident.cols > 0) ident.cols else 80;
1067|        self.clients.items[client_idx].rows = if (ident.rows > 0) ident.rows else 24;
1068|        self.clients.items[client_idx].xpixel = ident.xpixel;
1069|        self.clients.items[client_idx].ypixel = ident.ypixel;
