1077|    fn handleCommand(self: *Server, client_idx: usize, payload: []const u8) !void {
1078|        const client = &self.clients.items[client_idx];
1079|        var registry = cmd.Registry.init(self.allocator);
1080|        defer registry.deinit();
1081|        try registry.registerBuiltins();
1082|        var startup_attach_candidate = false;
1083|
1084|        var ctx = cmd.Context{
1085|            .server = self,
1086|            .session = client.session,
1087|            .window = if (client.session) |session| session.active_window else null,
1088|            .pane = if (client.session) |session| if (session.active_window) |window| window.active_pane else null else null,
1089|            .client_index = client_idx,
1090|            .allocator = self.allocator,
1091|            .reply_fd = client.fd,
1092|            .registry = &registry,
1093|            .binding_manager = &self.binding_manager,
1094|        };
1095|
1096|        if (std.mem.indexOfScalar(u8, payload, 0) != null) {
1097|            var args = try protocol.decodeCommandArgs(self.allocator, payload);
1098|            defer args.deinit(self.allocator);
1099|
1100|            if (args.items.len == 0) {
1101|                try self.sendError(client.fd, "empty command\n", 1);
1102|                return;
1103|            }
1104|            startup_attach_candidate = commandStartsStartupRelay(args.items[0]);
1105|
1106|            if (!std.mem.eql(u8, args.items[0], "choose-tree") and !(std.mem.eql(u8, args.items[0], "send-keys") and self.choose_tree_state != null)) {
1107|                try self.ensureCommandSession(&ctx, client.fd, args.items[0], &registry);
1108|            }
1109|            ctx.window = if (ctx.session) |session| session.active_window else null;
1110|            ctx.pane = if (ctx.window) |window| window.active_pane else null;
1111|
1112|            registry.execute(&ctx, args.items[0], args.items[1..]) catch |err| {
1113|                try self.sendError(client.fd, commandErrorMessage(err), 1);
1114|                return;
1115|            };
1116|        } else {
1117|            var parser = config_parser.ConfigParser.init(self.allocator, payload);
1118|            var commands = parser.parseAll() catch {
1119|                try self.sendError(client.fd, "failed to parse command\n", 1);
1120|                return;
1121|            };
1122|            defer {
1123|                for (commands.items) |*command| command.deinit(self.allocator);
1124|                commands.deinit(self.allocator);
1125|            }
1126|            if (commands.items.len == 0) {
1127|                try self.sendError(client.fd, "empty command\n", 1);
1128|                return;
1129|            }
1130|            startup_attach_candidate = commandStartsStartupRelay(commands.items[0].name);
1131|
1132|            for (commands.items) |*command| {
1133|                if (!std.mem.eql(u8, command.name, "choose-tree") and !(std.mem.eql(u8, command.name, "send-keys") and self.choose_tree_state != null)) {
1134|                    try self.ensureCommandSession(&ctx, client.fd, command.name, &registry);
1135|                }
1136|                ctx.window = if (ctx.session) |session| session.active_window else null;
1137|                ctx.pane = if (ctx.window) |window| window.active_pane else null;
1138|
1139|                registry.executeParsed(&ctx, command) catch |err| {
1140|                    try self.sendError(client.fd, commandErrorMessage(err), 1);
1141|                    return;
1142|                };
1143|            }
1144|        }
1145|
1146|        const prev_session = client.session;
1147|        self.setClientSession(client_idx, ctx.session);
1148|
1149|        // Send ready (enter interactive mode) when the command attached the
1150|        // client to a (possibly different) session. This covers:
1151|        //   - new-session: prev was null or different session
1152|        //   - attach-session: prev was null or different session
1153|        // Send exit_ack for non-attaching commands (list-sessions, etc.).
1154|        if (ctx.session != null and (prev_session == null or prev_session != ctx.session)) {
1155|            if (startup_attach_candidate) {
1156|                self.beginClientStartupRelay(client_idx);
1157|            }
1158|            try self.sendClientMessage(client.fd, .ready, &.{});
1159|            if (!startup_attach_candidate) {
1160|                if (ctx.session) |session| {
1161|                    self.renderActivePaneToClient(session, client.fd);
1162|                }
1163|            }
1164|        } else {
1165|            try self.sendClientMessageWithFlags(client.fd, .exit_ack, 0, &.{});
1166|        }
1167|    }
