1597|    /// Returns true if the payload was handled as a mouse event.
1598|    fn parseSgrMouse(
1599|        self: *Server,
1600|        payload: []const u8,
1601|        window: *Window,
1602|        default_pane: *Pane,
1603|    ) bool {
1604|        // SGR mouse format: ESC [ < Btn ; X ; Y [Mm]
1605|        // Minimum length: ESC [ < 0 ; 1 ; 1 M = 10 bytes
1606|        if (payload.len < 10) return false;
1607|        if (payload[1] != '[' or payload[2] != '<') return false;
