1636|        // Find which pane contains these coordinates.
1637|        var target_pane = default_pane;
1638|        for (window.panes.items) |pane| {
1639|            if (x >= pane.xoff and x < pane.xoff + pane.sx and
1640|                y >= pane.yoff and y < pane.yoff + pane.sy)
1641|            {
1642|                target_pane = pane;
1643|                break;
1644|            }
1645|        }
1646|
1647|        // Check if the target pane has mouse mode enabled.
1648|        if (self.session_loop.getPane(target_pane.id)) |ps| {
1649|            if (!ps.screen.mode.mouse_standard and !ps.screen.mode.mouse_button and
1650|                !ps.screen.mode.mouse_any)
