1727|    fn maybeExpireStartupRelay(self: *Server, client_idx: usize) void {
1728|        if (client_idx >= self.clients.items.len) return;
1729|        const client = &self.clients.items[client_idx];
1730|        if (client.relay_state != .startup_pending and client.relay_state != .startup_active) return;
1731|
1732|        const now = monotonicNs();
1733|        if (client.relay_started_at_ns != 0 and now - client.relay_started_at_ns >= std.time.ns_per_s) {
1734|            client.relay_state = .relay_done;
1735|            client.inflight_probe_requests.clearRetainingCapacity();
1736|            client.pending_probe_requests.clearRetainingCapacity();
1737|            if (client.session) |session| self.clearSessionRelayOwnerFd(session, client.fd);
1738|            var detail: [160]u8 = undefined;
1739|            const msg = std.fmt.bufPrint(&detail, "client_id={d} reason=timeout", .{client.client_id}) catch "";
1740|            startup_probe.traceEvent("server", "finish_relay", msg);
1741|            return;
1742|        }
1743|        if (client.relay_state == .startup_active and client.inflight_probe_requests.items.len == 0 and
1744|            client.pending_probe_requests.items.len == 0 and
1745|            now - client.relay_last_probe_ns >= 200 * std.time.ns_per_ms)
1746|        {
1747|            client.relay_state = .relay_done;
1748|            if (client.session) |session| self.clearSessionRelayOwnerFd(session, client.fd);
1749|            var detail: [160]u8 = undefined;
1750|            const msg = std.fmt.bufPrint(&detail, "client_id={d} reason=quiescence", .{client.client_id}) catch "";
1751|            startup_probe.traceEvent("server", "finish_relay", msg);
1752|        }
1753|    }
