1766|        const msg = std.fmt.bufPrint(&detail, "client_id={d} id={d} kind={s} pending={d}", .{ client.client_id, request_id, @tagName(kind), client.pending_probe_requests.items.len }) catch "";
1767|        startup_probe.traceEvent("server", "queue_probe_req", msg);
