1770|    fn flushStartupProbeBufferAsOutput(self: *Server, client_idx: usize, output: *std.ArrayListAligned(u8, null)) void {
1771|        if (client_idx >= self.clients.items.len) return;
1772|        const client = &self.clients.items[client_idx];
1773|        if (client.probe_parse_buffer.items.len == 0) return;
