1778|    fn filterStartupProbeOutput(self: *Server, client_idx: usize, input: []const u8, output: *std.ArrayListAligned(u8, null)) void {
1779|        const client = &self.clients.items[client_idx];
1780|        client.probe_parse_buffer.appendSlice(self.allocator, input) catch {
1781|            output.appendSlice(self.allocator, input) catch {};
1782|            return;
1783|        };
1784|
1785|        while (client.probe_parse_buffer.items.len > 0) {
1786|            const bytes = client.probe_parse_buffer.items;
1787|            if (bytes[0] != 0x1b) {
1788|                output.append(self.allocator, bytes[0]) catch {};
1789|                _ = client.probe_parse_buffer.orderedRemove(0);
1790|                continue;
1791|            }
1792|
1793|            var saw_prefix = false;
1794|            inline for ([_]startup_probe.ProbeKind{ .osc_10, .osc_11, .osc_12, .csi_primary_da, .xtversion }) |kind| {
1795|                const request = startup_probe.requestBytes(kind);
1796|                if (bytes.len >= request.len and std.mem.eql(u8, bytes[0..request.len], request)) {
1797|                    self.queueStartupProbeRequest(client_idx, kind);
1798|                    client.probe_parse_buffer.replaceRange(self.allocator, 0, request.len, &.{}) catch {};
1799|                    saw_prefix = true;
1800|                    break;
1801|                }
1802|                if (startup_probe.requestPrefixMatch(kind, bytes) == .prefix) {
1803|                    saw_prefix = true;
1804|                    return;
1805|                }
1806|            }
1807|            if (saw_prefix) continue;
1808|
1809|            output.append(self.allocator, bytes[0]) catch {};
1810|            _ = client.probe_parse_buffer.orderedRemove(0);
1811|        }
1812|    }
