1837|    fn handlePtyReadableRef(self: *Server, pane_ref: PaneRef) usize {
1838|        const session = pane_ref.session;
1839|        const pane = pane_ref.pane;
1840|        const fd = pane.fd;
1841|        var detail: [160]u8 = undefined;
1842|        const start_msg = std.fmt.bufPrint(&detail, "fd={d}", .{fd}) catch "";
1843|        startup_probe.traceEvent("server", "handle_pty_readable_begin", start_msg);
1844|        var buf: [4096]u8 = undefined;
1845|        const n = std.c.read(fd, &buf, buf.len);
1846|        if (n < 0) {
1847|            switch (std.posix.errno(n)) {
1848|                .AGAIN, .INTR => return 0,
1849|                else => return 0,
1850|            }
1851|        }
1852|        if (n == 0) {
1853|            if (!pane.flags.exited) {
1854|                pane.flags.exited = true;
1855|                self.fireHooks(.pane_exited);
1856|
1857|                for (session.windows.items) |window| {
1858|                    for (window.panes.items) |wp| {
1859|                        if (wp == pane and window.options.remain_on_exit) {
1860|                            if (self.session_loop.getPane(pane.id)) |ps| {
1861|                                const dead_msg = "[Pane is dead]";
1862|                                @import("input_handler.zig").processBytes(&ps.parser, &ps.screen, "\x1b[H\x1b[2J");
1863|                                @import("input_handler.zig").processBytes(&ps.parser, &ps.screen, dead_msg);
1864|                                ps.dirty.markAllDirty();
1865|                            }
1866|                            self.deactivatePaneFd(pane);
1867|                            return 0;
1868|                        }
1869|                    }
1870|                }
1871|            }
1872|            self.deactivatePaneFd(pane);
1873|            return 0;
1874|        }
1875|
1876|        if (self.ownerRelayClientIndexForSession(session)) |relay_client_idx| {
1877|            self.maybeExpireStartupRelay(relay_client_idx);
1878|        }
1879|
1880|        var filtered_output: std.ArrayListAligned(u8, null) = .empty;
1881|        defer filtered_output.deinit(self.allocator);
1882|
1883|        const owner_client_idx = self.ownerRelayClientIndexForSession(session);
1884|        if (owner_client_idx) |relay_client_idx| {
1885|            const relay_client = self.clients.items[relay_client_idx];
1886|            if (relay_client.relay_state == .startup_pending or relay_client.relay_state == .startup_active) {
1887|                self.filterStartupProbeOutput(relay_client_idx, buf[0..@intCast(n)], &filtered_output);
1888|                self.dispatchNextStartupProbe(relay_client_idx);
1889|                self.drainClient(relay_client_idx);
1890|            } else {
1891|                self.flushStartupProbeBufferAsOutput(relay_client_idx, &filtered_output);
1892|                filtered_output.appendSlice(self.allocator, buf[0..@intCast(n)]) catch {};
1893|            }
1894|        } else {
1895|            filtered_output.appendSlice(self.allocator, buf[0..@intCast(n)]) catch {};
1896|        }
1897|
1898|        const pane_state = self.session_loop.getPane(pane.id);
1899|        if (pane_state) |ps| {
1900|            ps.processPtyOutput(filtered_output.items);
1901|        }
1902|
1903|        if (pane.pid > 0) {
1904|            for (session.windows.items) |window| {
1905|                if (window.active_pane == pane) {
1906|                    if (platform.getProcessName(self.allocator, pane.pid) catch null) |new_name| {
1907|                        defer self.allocator.free(new_name);
1908|                        if (!std.mem.eql(u8, window.name, new_name)) {
1909|                            window.rename(new_name) catch {};
1910|                        }
1911|                    }
1912|                    break;
1913|                }
1914|            }
1915|        }
1916|
1917|        const relay_render_bypass = if (owner_client_idx) |relay_client_idx|
1918|            self.clients.items[relay_client_idx].relay_state == .startup_pending or
1919|                self.clients.items[relay_client_idx].relay_state == .startup_active
1920|        else
1921|            false;
1922|
1923|        const client_fds = self.sessionClientFds(session);
1924|        if (client_fds.len > 0) {
1925|            for (client_fds) |client_fd| {
1926|                const client_idx = self.clientIndexFromRegistry(client_fd) orelse continue;
1927|                if (relay_render_bypass) {
1928|                    self.queueClientMessage(client_idx, .output, filtered_output.items);
1929|                    continue;
1930|                }
1931|                self.renderComposedToClient(client_fd, session, pane_state) catch {
1932|                    self.queueClientMessage(client_idx, .output, filtered_output.items);
1933|                };
1934|            }
1935|        } else {
1936|            for (self.clients.items, 0..) |client, client_idx| {
1937|                if (client.session != session) continue;
1938|                if (relay_render_bypass) {
1939|                    self.queueClientMessage(client_idx, .output, filtered_output.items);
1940|                    continue;
1941|                }
1942|                self.renderComposedToClient(client.fd, session, pane_state) catch {
1943|                    self.queueClientMessage(client_idx, .output, filtered_output.items);
1944|                };
1945|            }
1946|        }
1947|
1948|        const end_msg = std.fmt.bufPrint(&detail, "fd={d} bytes={d}", .{ fd, n }) catch "";
1949|        startup_probe.traceEvent("server", "handle_pty_readable_end", end_msg);
1950|        return @intCast(n);
1951|    }
