1988|    /// Render the composed terminal view (screen content + status bar) for a
1989|    /// client.  Uses a pipe pair so the existing Output→fd writer can produce
1990|    /// escape sequences that we then wrap in a protocol message.
1991|    fn renderComposedToClient(
1992|        self: *Server,
1993|        client_fd: std.c.fd_t,
1994|        session: *Session,
1995|        pane_state_opt: ?*server_loop.PaneState,
1996|    ) !void {
1997|        if (self.sessionStartupRelayActive(session)) return error.StartupRelayActive;
1998|        var detail: [160]u8 = undefined;
1999|        const start_msg = std.fmt.bufPrint(&detail, "client_fd={d}", .{client_fd}) catch "";
2000|        startup_probe.traceEvent("server", "render_composed_begin", start_msg);
2001|        _ = pane_state_opt;
2002|
2003|        const redraw_mod = @import("screen/redraw.zig");
2004|        var rendered: [protocol.max_payload]u8 = undefined;
2005|        var capture = output_mod.Output.Capture.init(rendered[0..]);
2006|        var out = output_mod.Output.initCapture(&capture);
2007|
2008|        // Render all panes in the active window at their layout offsets.
2009|        const window = session.active_window orelse {
2010|            return error.NoPaneState;
2011|        };
2012|        const pane_count = window.panes.items.len;
2013|        const active_cursor = self.getActiveCursorState(session, window);
2014|        const cols: u32 = window.sx;
2015|        const rows: u32 = window.sy;
2016|        const pane_yoff = statusContentOffset(session);
2017|        const pane_rows = statusContentRows(session, rows);
2018|
2019|        if (pane_count > 1) {
2020|            out.hideCursor();
2021|        }
2022|        for (window.panes.items) |pane| {
2023|            if (self.session_loop.getPane(pane.id)) |ps| {
2024|                const available_rows = pane_rows -| pane.yoff;
2025|                redraw_mod.redrawAtClipped(&ps.dirty, &ps.screen, &out, pane.xoff, pane.yoff + pane_yoff, available_rows);
2026|            }
2027|        }
2028|
2029|        if (pane_count > 1) {
2030|            if (window.layout_root) |root| {
2031|                self.drawLayoutBorders(&out, root, window.sx, pane_rows, pane_yoff);
2032|            }
2033|        }
2034|
2035|        try self.renderStatusBar(&out, session, window, cols, rows);
2036|
2037|        restoreActiveCursor(&out, active_cursor);
2038|
2039|        out.flush();
2040|
2041|        if (capture.len > 0) {
2042|            try self.sendClientMessage(client_fd, .output, capture.written());
2043|        }
2044|        const end_msg = std.fmt.bufPrint(&detail, "client_fd={d} bytes={d} truncated={any}", .{ client_fd, capture.len, capture.truncated }) catch "";
2045|        startup_probe.traceEvent("server", "render_composed_end", end_msg);
2046|    }
