2048|    /// Recursively draw border lines between panes based on the layout tree.
2049|    fn drawLayoutBorders(
2050|        self: *Server,
2051|        out: *output_mod.Output,
2052|        cell: *const @import("layout/layout.zig").LayoutCell,
2053|        total_cols: u32,
2054|        total_rows: u32,
2055|        y_offset: u32,
2056|    ) void {
2057|        if (cell.cell_type == .pane) return;
2058|
2059|        const children = cell.children.items;
2060|        if (children.len < 2) {
2061|            for (children) |child| {
2062|                self.drawLayoutBorders(out, child, total_cols, total_rows, y_offset);
2063|            }
2064|            return;
2065|        }
2066|
2067|        // Draw borders between adjacent children.
2068|        for (children[0 .. children.len - 1]) |child| {
2069|            if (cell.cell_type == .horizontal) {
2070|                // Vertical border: draw at (child.xoff + child.sx, child.yoff) to (child.xoff + child.sx, child.yoff + child.sy - 1)
2071|                const bx = child.xoff + child.sx;
2072|                const top = child.yoff;
2073|                const bottom = @min(child.yoff + child.sy, total_rows) -| 1;
2074|                out.attrReset();
2075|                var y = top;
2076|                while (y <= bottom) : (y += 1) {
2077|                    out.cursorTo(bx, y + y_offset);
2078|                    out.writeBytes("\xe2\x94\x82"); // U+2502 │
2079|                }
2080|            } else if (cell.cell_type == .vertical) {
2081|                // Horizontal border: draw at (child.xoff, child.yoff + child.sy) to (child.xoff + child.sx - 1, child.yoff + child.sy)
2082|                const by = child.yoff + child.sy;
2083|                if (by >= total_rows) continue;
2084|                const left = child.xoff;
2085|                const right = child.xoff + child.sx -| 1;
2086|                out.attrReset();
2087|                out.cursorTo(left, by + y_offset);
2088|                var x = left;
2089|                while (x <= right) : (x += 1) {
2090|                    out.writeBytes("\xe2\x94\x80"); // U+2500 ─
2091|                }
2092|            }
2093|        }
2094|
2095|        // Recurse into children.
2096|        for (children) |child| {
2097|            self.drawLayoutBorders(out, child, total_cols, total_rows, y_offset);
2098|        }
2099|    }
