2101|    /// Drain all pending messages on a newly accepted client.
2102|    /// Called after accepting a client to handle data that arrived before the
2103|    /// next poll iteration.
2104|    fn drainClient(self: *Server, client_idx: usize) void {
2105|        if (client_idx >= self.clients.items.len) return;
2106|        const fd = self.clients.items[client_idx].fd;
2107|        var detail: [192]u8 = undefined;
2108|        const start_msg = std.fmt.bufPrint(&detail, "client_id={d} fd={d}", .{ self.clients.items[client_idx].client_id, fd }) catch "";
2109|        startup_probe.traceEvent("server", "drain_client_start", start_msg);
2110|
2111|        // Set non-blocking temporarily so we don't hang.
2112|        const fl = std.c.fcntl(fd, std.c.F.GETFL);
2113|        if (fl >= 0) {
2114|            _ = std.c.fcntl(fd, std.c.F.SETFL, fl | @as(i32, @bitCast(std.c.O{ .NONBLOCK = true })));
2115|        }
2116|        defer if (fl >= 0) {
2117|            _ = std.c.fcntl(fd, std.c.F.SETFL, fl);
2118|        };
2119|
2120|        // Process up to a few messages (identify + command typically).
2121|        // Break on WouldBlock (no more data) without removing the client.
2122|        var count: usize = 0;
2123|        while (count < 8) : (count += 1) {
2124|            if (client_idx >= self.clients.items.len) break;
2125|            self.handleClientReadable(client_idx) catch |err| switch (err) {
2126|                error.WouldBlock => {
2127|                    const msg = std.fmt.bufPrint(&detail, "client_id={d} fd={d} count={d}", .{ self.clients.items[client_idx].client_id, fd, count }) catch "";
2128|                    startup_probe.traceEvent("server", "drain_client_wouldblock", msg);
2129|                    break;
2130|                }, // no more data, normal for non-blocking
2131|                else => break,
2132|            };
2133|        }
2134|    }
2135|
2136|    fn removeClient(self: *Server, client_idx: usize) void {
2137|        if (client_idx >= self.clients.items.len) return;
2138|        var client = self.clients.orderedRemove(client_idx);
2139|        self.unregisterReadableFd(client.fd);
