 433|    fn writeStyledStatusLine(out: *output_mod.Output, base_style: status_style.Style, line: []const u8) void {
 434|        var active_style = base_style;
 435|        applyStatusStyle(out, active_style);
 436|
 437|        var i: usize = 0;
 438|        while (i < line.len) {
 439|            if (i + 1 < line.len and line[i] == '#' and line[i + 1] == '[') {
 440|                if (status_style.markerEnd(line, i)) |end| {
 441|                    active_style = status_style.apply(active_style, line[i..end]);
 442|                    applyStatusStyle(out, active_style);
 443|                    i = end;
 444|                    continue;
 445|                }
 446|            }
 447|
 448|            const next_marker = std.mem.indexOfPos(u8, line, i, "#[") orelse line.len;
 449|            out.writeBytes(line[i..next_marker]);
 450|            i = next_marker;
 451|        }
 452|    }
