 492|    fn refreshStatusClientsIfDue(self: *Server) void {
 493|        var now: i64 = 0;
 494|        _ = time(&now);
 495|
 496|        for (self.sessions.items) |session| {
 497|            if (session.attached == 0 and !self.hasClientForSession(session)) continue;
 498|            if (self.sessionStartupRelayActive(session)) continue;
 499|            if (!session.options.status or session.options.status_interval == 0) continue;
 500|
 501|            if (session.status_next_refresh_at == 0) {
 502|                session.status_next_refresh_at = now + @as(i64, @intCast(session.options.status_interval));
 503|                continue;
 504|            }
 505|            if (now < session.status_next_refresh_at) continue;
 506|
 507|            const window = session.active_window orelse continue;
 508|            const pane = window.active_pane orelse continue;
 509|            const pane_state = self.session_loop.getPane(pane.id) orelse continue;
 510|            pane_state.dirty.markAllDirty();
 511|
 512|            const client_fds = self.sessionClientFds(session);
 513|            if (client_fds.len > 0) {
 514|                for (client_fds) |client_fd| {
 515|                    self.renderComposedToClient(client_fd, session, pane_state) catch {};
 516|                }
 517|            } else {
 518|                for (self.clients.items) |client| {
 519|                    if (client.session != session) continue;
 520|                    self.renderComposedToClient(client.fd, session, pane_state) catch {};
 521|                }
 522|            }
 523|            session.status_next_refresh_at = now + @as(i64, @intCast(session.options.status_interval));
 524|        }
 525|    }
