 559|    fn addSessionClientFd(self: *Server, session: *Session, fd: std.c.fd_t) void {
 560|        if (fd < 0) return;
 561|        const gop = self.session_client_fds.getOrPut(session) catch return;
 562|        if (!gop.found_existing) {
 563|            gop.value_ptr.* = .empty;
 564|        }
 565|        for (gop.value_ptr.items) |existing_fd| {
 566|            if (existing_fd == fd) return;
 567|        }
 568|        gop.value_ptr.append(self.allocator, fd) catch {};
