 599|    fn nextStatusRefreshDelayMs(self: *const Server, now: i64) ?c_int {
 600|        var next_refresh_at: ?i64 = null;
 601|
 602|        for (self.sessions.items) |session| {
 603|            if (session.attached == 0 and !self.hasClientForSession(session)) continue;
 604|            if (self.sessionStartupRelayActive(session)) continue;
 605|            if (!session.options.status or session.options.status_interval == 0) continue;
 606|
 607|            if (session.status_next_refresh_at == 0 or session.status_next_refresh_at <= now) {
 608|                return 0;
 609|            }
 610|
 611|            next_refresh_at = if (next_refresh_at) |current|
 612|                @min(current, session.status_next_refresh_at)
 613|            else
 614|                session.status_next_refresh_at;
 615|        }
 616|
 617|        const refresh_at = next_refresh_at orelse return null;
 618|        const delay_s = @max(refresh_at - now, 0);
 619|        const delay_ms: i64 = delay_s * std.time.ms_per_s;
 620|        return @intCast(@min(delay_ms, idle_poll_timeout_ms));
 621|    }
 622|
 623|    fn nextPollTimeoutMs(self: *const Server) c_int {
 624|        if (self.hasPendingClientOutput() or self.hasPendingPaneWrites()) {
 625|            return pending_write_retry_timeout_ms;
 626|        }
 627|
 628|        var now: i64 = 0;
 629|        _ = time(&now);
 630|        return self.nextStatusRefreshDelayMs(now) orelse idle_poll_timeout_ms;
 631|    }
