 691|    pub fn listen(self: *Server) !void {
 692|        try self.ensureSocketDir();
 693|        self.removeStaleSocket();
 694|        const io = self.std_io_runtime.io();
 695|        const address = try std.Io.net.UnixAddress.init(self.socket_path);
 696|        const listen_server = try address.listen(io, .{
 697|            .kernel_backlog = 128,
 698|        });
 699|        self.listen_fd = listen_server.socket.handle;
 700|        errdefer self.listen_fd = -1;
 701|        try self.registerReadableFd(self.listen_fd, .listen);
 702|
 703|        var path_buf: [256]u8 = .{0} ** 256;
 704|        if (self.socket_path.len < path_buf.len) {
 705|            @memcpy(path_buf[0..self.socket_path.len], self.socket_path);
 706|            _ = std.c.chmod(@ptrCast(path_buf[0..self.socket_path.len :0]), 0o700);
 707|        }
 708|
 709|        self.running = true;
 710|
 711|        // Set default shell from $SHELL (like tmux).
 712|        if (self.global_default_shell == null) {
 713|            const shell_env = std.c.getenv("SHELL");
 714|            if (shell_env) |s| {
 715|                const shell_slice = std.mem.sliceTo(s, 0);
 716|                if (shell_slice.len > 0) {
 717|                    self.global_default_shell = self.allocator.dupeZ(u8, shell_slice) catch null;
 718|                }
 719|            }
 720|        }
 721|
 722|        log.info("server listening on {s}", .{self.socket_path});
 723|    }
