 725|    /// Load a configuration file by executing it as commands.
 726|    /// Returns true once a file was successfully opened, even if it was empty.
 727|    pub fn loadConfigFile(self: *Server, path: []const u8) bool {
 728|        const expanded_path = config_path.expandHomePath(self.allocator, path) catch return false;
 729|        defer self.allocator.free(expanded_path);
 730|
 731|        var path_buf: [4096]u8 = .{0} ** 4096;
 732|        if (expanded_path.len >= path_buf.len) return false;
 733|        @memcpy(path_buf[0..expanded_path.len], expanded_path);
 734|        const cpath: [*:0]const u8 = @ptrCast(path_buf[0..expanded_path.len :0]);
 735|        const fd = std.c.open(cpath, .{ .ACCMODE = .RDONLY }, @as(std.c.mode_t, 0));
 736|        if (fd < 0) return false;
 737|        defer _ = std.c.close(fd);
 738|
 739|        var content_buf: [65536]u8 = undefined;
 740|        var total: usize = 0;
 741|        while (total < content_buf.len) {
 742|            const n = std.c.read(fd, content_buf[total..].ptr, content_buf.len - total);
 743|            if (n <= 0) break;
 744|            total += @intCast(n);
 745|        }
 746|        if (total == 0) return true;
 747|
 748|        var registry = cmd.Registry.init(self.allocator);
 749|        defer registry.deinit();
 750|        registry.registerBuiltins() catch return true;
 751|
 752|        var ctx = cmd.Context{
 753|            .server = self,
 754|            .session = self.default_session,
 755|            .window = if (self.default_session) |s| s.active_window else null,
 756|            .pane = if (self.default_session) |s| if (s.active_window) |w| w.active_pane else null else null,
 757|            .allocator = self.allocator,
 758|            .registry = &registry,
 759|            .binding_manager = &self.binding_manager,
 760|        };
 761|
 762|        var parser = config_parser.ConfigParser.init(self.allocator, content_buf[0..total]);
 763|        var commands = parser.parseAll() catch return true;
 764|        defer {
 765|            for (commands.items) |*command| command.deinit(self.allocator);
 766|            commands.deinit(self.allocator);
 767|        }
 768|
 769|        for (commands.items) |*command| {
 770|            registry.executeParsed(&ctx, command) catch {};
 771|        }
 772|        return true;
 773|    }
