 788|        const hook_list = self.hook_registry.fire(hook_type);
 789|        if (hook_list.len == 0) return;
 790|
 791|        var registry = cmd.Registry.init(self.allocator);
 792|        defer registry.deinit();
 793|        registry.registerBuiltins() catch return;
 794|
 795|        var ctx = cmd.Context{
 796|            .server = self,
 797|            .session = self.default_session,
 798|            .window = if (self.default_session) |s| s.active_window else null,
 799|            .pane = if (self.default_session) |s| if (s.active_window) |w| w.active_pane else null else null,
 800|            .allocator = self.allocator,
 801|            .registry = &registry,
 802|            .binding_manager = &self.binding_manager,
 803|        };
 804|
 805|        for (hook_list) |hook| {
