 808|            defer {
 809|                for (commands.items) |*command| command.deinit(self.allocator);
 810|                commands.deinit(self.allocator);
 811|            }
 812|            for (commands.items) |*command| {
 813|                registry.executeParsed(&ctx, command) catch {};
 814|            }
 815|        }
 816|    }
