 818|    pub fn createSession(self: *Server, name: []const u8, shell: [:0]const u8, cols: u32, rows: u32) !*Session {
 819|        const session = try Session.init(self.allocator, name);
 820|        errdefer session.deinit();
 821|        try self.applySessionStatusDefaults(session);
 822|
 823|        const window = try Window.init(self.allocator, name, cols, rows);
 824|        errdefer window.deinit();
 825|        try self.applyWindowDefaults(window);
 826|
 827|        const pane = try Pane.init(self.allocator, cols, rows);
 828|        errdefer pane.deinit();
 829|
 830|        var pty = try Pty.openPty();
 831|        try pty.forkExec(shell, null);
 832|        pty.resize(@intCast(cols), @intCast(rows));
 833|        pane.fd = pty.master_fd;
 834|        pane.pid = pty.pid;
 835|
 836|        try window.addPane(pane);
 837|        try session.addWindow(window);
 838|        try self.sessions.append(self.allocator, session);
 839|        if (self.default_session == null) self.default_session = session;
 840|        // Use trackPane to register the pane for I/O processing and perform an
 841|        // immediate drain on any startup output already waiting on the PTY.
 842|        try self.trackPane(pane, cols, rows);
 843|
 844|        self.fireHooks(.after_new_session);
 845|
 846|        return session;
 847|    }
