 849|    pub fn acceptClient(self: *Server) !void {
 850|        const io = self.std_io_runtime.io();
 851|        var listen_server = std.Io.net.Server{
 852|            .socket = .{
 853|                .handle = self.listen_fd,
 854|                .address = .{ .ip4 = .loopback(0) },
 855|            },
 856|            .options = if (std.Io.net.Server.AcceptOptions != void)
 857|                .{ .mode = .stream, .protocol = null }
 858|            else {},
 859|        };
 860|        var client_stream = listen_server.accept(io) catch |err| switch (err) {
 861|            error.WouldBlock, error.ConnectionAborted => return,
 862|            else => return err,
 863|        };
 864|        errdefer client_stream.close(io);
 865|
 866|        const client_fd = client_stream.socket.handle;
 867|        setFdNonblocking(client_fd);
 868|        const client_id = self.next_client_id;
 869|        self.next_client_id += 1;
 870|        const client_idx = self.clients.items.len;
 871|        try self.registerReadableFd(client_fd, .{ .client = client_idx });
 872|        errdefer self.unregisterReadableFd(client_fd);
 873|        try self.clients.append(self.allocator, .{
 874|            .fd = client_fd,
 875|            .session = null,
 876|            .identified = false,
 877|            .choose_tree_state = null,
 878|            .client_id = client_id,
 879|        });
 880|        client_stream.socket.handle = -1;
 881|        self.drainClient(client_idx);
 882|    }
