1121|            };
1122|            defer {
1123|                for (commands.items) |*command| command.deinit(self.allocator);
1124|                commands.deinit(self.allocator);
1125|            }
1126|            if (commands.items.len == 0) {
1127|                try self.sendError(client.fd, "empty command\n", 1);
1128|                return;
1129|            }
1130|            startup_attach_candidate = commandStartsStartupRelay(commands.items[0].name);
1131|
1132|            for (commands.items) |*command| {
1133|                if (!std.mem.eql(u8, command.name, "choose-tree") and !(std.mem.eql(u8, command.name, "send-keys") and self.choose_tree_state != null)) {
