1135|                }
1136|                ctx.window = if (ctx.session) |session| session.active_window else null;
1137|                ctx.pane = if (ctx.window) |window| window.active_pane else null;
1138|
1139|                registry.executeParsed(&ctx, command) catch |err| {
1140|                    try self.sendError(client.fd, commandErrorMessage(err), 1);
1141|                    return;
1142|                };
1143|            }
