1294|                .key = ' ',
1295|                .mods = .{ .ctrl = true },
1296|            };
1297|        }
1298|        if (byte < 27) {
1299|            return .{
1300|                .key = @as(u21, 'a') + byte - 1,
1301|                .mods = .{ .ctrl = true },
1302|            };
1303|        }
1304|        if (byte < 32) {
1305|            return .{
1306|                .key = @as(u21, byte) + '@',
1307|                .mods = .{ .ctrl = true },
1308|            };
1309|        }
1310|        return .{
1311|            .key = byte,
1312|            .mods = .{},
1313|        };
1314|    }
