1325|    fn normalizePrefixKey(prefix_key: u21) ?u21 {
1326|        if (prefix_key == 0) return ' ';
1327|        if (prefix_key < 27) return @as(u21, 'a') + prefix_key - 1;
1328|        if (prefix_key < 32) return prefix_key + '@';
1329|        return prefix_key;
