1594|    /// Parse an SGR mouse sequence (ESC[<btn;x;yM or ESC[<btn;x;ym),
1595|    /// find the target pane by coordinates, adjust coordinates to pane-local,
1596|    /// and forward the adjusted sequence to the pane's PTY.
1597|    /// Returns true if the payload was handled as a mouse event.
1598|    fn parseSgrMouse(
1599|        self: *Server,
1600|        payload: []const u8,
1601|        window: *Window,
1602|        default_pane: *Pane,
1603|    ) bool {
1604|        // SGR mouse format: ESC [ < Btn ; X ; Y [Mm]
1605|        // Minimum length: ESC [ < 0 ; 1 ; 1 M = 10 bytes
1606|        if (payload.len < 10) return false;
1607|        if (payload[1] != '[' or payload[2] != '<') return false;
1608|
1609|        const final = payload[payload.len - 1];
1610|        if (final != 'M' and final != 'm') return false;
1611|
1612|        // Parse btn;x;y from payload[3..len-1]
1613|        const params = payload[3 .. payload.len - 1];
1614|        var parts: [3]u32 = .{ 0, 0, 0 };
1615|        var part_idx: usize = 0;
1616|        for (params) |c| {
1617|            if (c == ';') {
1618|                part_idx += 1;
1619|                if (part_idx >= 3) return false;
1620|            } else if (c >= '0' and c <= '9') {
1621|                parts[part_idx] = parts[part_idx] * 10 + (c - '0');
1622|            } else {
1623|                return false; // unexpected character
1624|            }
1625|        }
1626|        if (part_idx != 2) return false;
1627|
1628|        const btn = parts[0];
1629|        const abs_x = parts[1];
1630|        const abs_y = parts[2];
1631|
1632|        // Convert from 1-based to 0-based.
1633|        const x = if (abs_x > 0) abs_x - 1 else 0;
1634|        const y = if (abs_y > 0) abs_y - 1 else 0;
1635|
1636|        // Find which pane contains these coordinates.
1637|        var target_pane = default_pane;
1638|        for (window.panes.items) |pane| {
1639|            if (x >= pane.xoff and x < pane.xoff + pane.sx and
1640|                y >= pane.yoff and y < pane.yoff + pane.sy)
1641|            {
1642|                target_pane = pane;
1643|                break;
1644|            }
1645|        }
1646|
1647|        // Check if the target pane has mouse mode enabled.
1648|        if (self.session_loop.getPane(target_pane.id)) |ps| {
1649|            if (!ps.screen.mode.mouse_standard and !ps.screen.mode.mouse_button and
1650|                !ps.screen.mode.mouse_any)
1651|            {
1652|                // Mouse not enabled on this pane — select pane on click.
1653|                if (final == 'M' and btn == 0) {
1654|                    window.selectPane(target_pane);
1655|                }
1656|                return true;
1657|            }
1658|        }
1659|
1660|        // Adjust coordinates to pane-local (1-based).
1661|        const local_x = x - target_pane.xoff + 1;
1662|        const local_y = y - target_pane.yoff + 1;
1663|
1664|        // Rebuild and forward the adjusted SGR mouse sequence.
1665|        var buf: [32]u8 = undefined;
1666|        const seq = std.fmt.bufPrint(&buf, "\x1b[<{d};{d};{d}{c}", .{
1667|            btn, local_x, local_y, final,
1668|        }) catch return false;
1669|
1670|        self.writePaneInput(target_pane, seq);
1671|        return true;
1672|    }
