 232|    pub fn deinit(self: *Server) void {
 233|        self.stop();
 234|        for (self.sessions.items) |session| {
 235|            session.deinit();
 236|        }
 237|        self.sessions.deinit(self.allocator);
 238|        for (self.clients.items) |*client| {
 239|            client.deinit(self.allocator);
 240|        }
 241|        self.clients.deinit(self.allocator);
 242|        {
 243|            var pending_iter = self.pending_pane_writes.iterator();
 244|            while (pending_iter.next()) |entry| {
 245|                entry.value_ptr.deinit(self.allocator);
 246|            }
 247|            self.pending_pane_writes.deinit();
 248|        }
 249|        if (self.choose_tree_state) |*state| {
 250|            state.deinit();
 251|        }
 252|        self.paste_stack.deinit();
 253|        self.session_loop.deinit();
 254|        self.binding_manager.deinit();
 255|        self.hook_registry.deinit();
 256|        {
 257|            var wc_iter = self.wait_channels.iterator();
 258|            while (wc_iter.next()) |entry| {
 259|                self.allocator.free(entry.key_ptr.*);
 260|                entry.value_ptr.deinit(self.allocator);
 261|            }
 262|            self.wait_channels.deinit();
 263|        }
 264|        for (self.prompt_history.items) |h| self.allocator.free(h);
 265|        self.prompt_history.deinit(self.allocator);
 266|        for (self.acl_entries.items) |entry| self.allocator.free(entry.user);
 267|        self.acl_entries.deinit(self.allocator);
 268|        if (self.global_default_shell) |shell| self.allocator.free(shell);
 269|        self.allocator.free(self.session_status_defaults.status_left);
 270|        self.allocator.free(self.session_status_defaults.status_right);
 271|        self.allocator.free(self.window_defaults.mode_keys);
 272|        self.allocator.free(self.window_defaults.window_status_format);
 273|        self.allocator.free(self.window_defaults.window_status_current_format);
 274|        self.status_command_cache.deinit();
 275|        for (self.messages.items) |msg| self.allocator.free(msg);
 276|        self.messages.deinit(self.allocator);
 277|        self.fd_registry.deinit();
 278|        self.pane_registry.deinit();
 279|        self.pending_client_fds.deinit();
 280|        {
 281|            var iter = self.session_client_fds.iterator();
 282|            while (iter.next()) |entry| {
 283|                entry.value_ptr.deinit(self.allocator);
 284|            }
 285|            self.session_client_fds.deinit();
 286|        }
 287|        self.session_relay_owner_fds.deinit();
 288|        self.fd_poller.deinit();
 289|        self.std_io_runtime.deinit();
 290|        self.allocator.free(self.socket_path);
 291|    }
