 571|    fn removeSessionClientFd(self: *Server, session: *Session, fd: std.c.fd_t) void {
 572|        const client_fds = self.session_client_fds.getPtr(session) orelse return;
 573|        for (client_fds.items, 0..) |existing_fd, idx| {
 574|            if (existing_fd == fd) {
 575|                _ = client_fds.swapRemove(idx);
 576|                break;
 577|            }
 578|        }
 579|        if (client_fds.items.len == 0) {
 580|            if (self.session_client_fds.fetchRemove(session)) |entry| {
 581|                var fds = entry.value;
 582|                fds.deinit(self.allocator);
 583|            }
 584|        }
 585|    }
